          code: "<!doctype html>\n<html lang=\"ko\"><head><meta charset=\"utf-8\"><title>form state</title></head>\n<body><form id=\"signup\">\n  <label>이름 <input name=\"displayName\" value=\"초기\"></label>\n  <label>요금제 <select name=\"plan\"><option value=\"basic\" selected>기본</option><option value=\"pro\">프로</option></select></label>\n  <label><input id=\"selectAll\" type=\"checkbox\"> 모두 동의</label>\n  <label><input class=\"agree\" type=\"checkbox\" name=\"agreements\" value=\"terms\" checked> 이용약관</label>\n  <label><input class=\"agree\" type=\"checkbox\" name=\"agreements\" value=\"privacy\"> 개인정보</label>\n  <label><input class=\"agree\" type=\"checkbox\" name=\"agreements\" value=\"marketing\" checked> 마케팅</label>\n  <button id=\"next\" type=\"submit\" disabled>다음</button>\n</form><pre id=\"out\"></pre>\n<script>\n  const form = document.querySelector('#signup');\n  const selectAll = document.querySelector('#selectAll');\n  const agrees = [...document.querySelectorAll('.agree')];\n  const next = document.querySelector('#next');\n  const lines = [];\n  form.elements.displayName.value = '민지';\n  form.elements.plan.value = 'pro';\n  function render(label) {\n    const checked = agrees.filter(item => item.checked);\n    const all = agrees.length > 0 && checked.length === agrees.length;\n    const some = checked.length > 0;\n    selectAll.checked = all;\n    selectAll.indeterminate = some && !all;\n    next.disabled = !all;\n    const data = new FormData(form);\n    const summary = `name=${form.elements.displayName.value},plan=${form.elements.plan.value},agreements=${data.getAll('agreements').join('|')}`;\n    lines.push(`${label}:${summary},all=${selectAll.checked},mixed=${selectAll.indeterminate},nextDisabled=${next.disabled}`);\n  }\n  render('initial');\n  agrees.forEach(item => { item.checked = true; });\n  render('after-all');\n  agrees[1].checked = false;\n  render('after-one-off');\n  document.querySelector('#out').textContent = lines.join('\\n');\n</script></body></html>",
